export function getSpeechesByCategory(category: SpeechCategory): MotivationalSpeech[] {
  return MOTIVATIONAL_SPEECHES.filter(s => s.category === category);
}

export function getRandomSpeech(category?: SpeechCategory): MotivationalSpeech {
  const pool = category ? getSpeechesByCategory(category) : MOTIVATIONAL_SPEECHES;
  return pool[Math.floor(Math.random() * pool.length)];
}
